import{_ as t,o as e,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"10. Anti Discrimination","description":"","frontmatter":{"title":"10. Anti Discrimination","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["flexible-work","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/mspp/operation/10-anti-discrimination.md","filePath":"ebas/mspp/operation/10-anti-discrimination.md"}'),o={name:"ebas/mspp/operation/10-anti-discrimination.md"};function r(s,i,c,p,l,m){return e(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="_10-anti-discrimination" tabindex="-1">10. Anti Discrimination <a class="header-anchor" href="#_10-anti-discrimination" aria-label="Permalink to &quot;10. Anti Discrimination&quot;">​</a></h1><p><strong>a.</strong> It is the intention of the parties to this Agreement to achieve the principal object in s.3(e) of the Act through respecting and valuing the diversity of the work force by helping to prevent and eliminate discrimination on the basis of race, colour, sex, sexual preference, age, physical or mental disability, marital status, family responsibilities, pregnancy, religion, political opinion, national extraction or social origin.</p><p><strong>b.</strong> Accordingly, in fulfilling their obligations under the disputes avoidance clause, the respondents must make every endeavour to ensure that neither the Agreement provisions nor their operation are directly or indirectly discriminatory in their effects.</p><p><strong>c.</strong> Nothing in this clause is taken to effect:</p><p><strong>(i)</strong> any different treatment (or treatment having different effects) which is specifically exempted under the Commonwealth anti-discrimination legislation;</p><p><strong>(ii)</strong> an Employee, Employer or registered organisation, pursuing matters of discrimination in any State or federal jurisdiction, including by application to the Human Rights and Equal Opportunity Commission;</p><p><strong>(iii)</strong> the exemptions under the Act.</p><p>Plain language terms: discrimination, equal opportunity.</p>',8)])])}const g=t(o,[["render",r]]);export{h as __pageData,g as default};
